import React from 'react';
import { createStyles, makeStyles } from '@material-ui/core';
import { Text } from '../Text';

type Props = {
  imageSrc: string;
  label: string;
};

const useStyles = makeStyles(
  () =>
    createStyles({
      image: {
        width: '100%',
      },

      label: {
        marginTop: 10,
      },
    }),
  { name: 'LabelledImage' },
);

export function LabelledImage({ imageSrc, label }: Props) {
  const classes = useStyles();

  return (
    <div>
      <img src={imageSrc} alt="" className={classes.image} />
      <Text variant="text" className={classes.label}>
        {label}
      </Text>
    </div>
  );
}
