import React from 'react';
import {
  createStyles,
  Grid,
  makeStyles,
  Link as LinkComponent,
} from '@material-ui/core';
import { Link, Text } from 'src/components';
import { Arrow } from 'src/icons';

type Action = {
  label: string;
  href: string;
};

type Props = {
  action: Action;
};

const useStyles = makeStyles(
  () =>
    createStyles({
      container: {
        paddingTop: 180,
        paddingBottom: 140,
      },

      arrow: {
        marginLeft: 75,
      },
    }),
  { name: 'FooterAction' },
);

export function FooterAction({ action }: Props) {
  const classes = useStyles();

  return (
    <Grid container justifyContent="center" className={classes.container}>
      <Grid item>
        <Grid
          container
          alignItems="center"
          justifyContent="center"
          component={Link}
          href={action.href}
        >
          <Grid item>
            <LinkComponent color="inherit" underline="always">
              <Text variant="title-middle">{action.label}</Text>
            </LinkComponent>
          </Grid>
          <Grid item>
            <Arrow className={classes.arrow} />
          </Grid>
        </Grid>
      </Grid>
    </Grid>
  );
}
