import React, { PropsWithChildren } from 'react';
import clsx from 'clsx';
import { createStyles, makeStyles } from '@material-ui/core';

type Props = {
  fullWidth?: boolean;
};

const useStyles = makeStyles(
  (theme) => {
    const { lg } = theme.breakpoints.values;
    const s2 = theme.spacing(2);
    const s3 = theme.spacing(3);

    return createStyles({
      container: {
        marginLeft: -s2,
        marginRight: -s2,

        [theme.breakpoints.up('sm')]: {
          marginLeft: -s3,
          marginRight: -s3,
        },
      },

      fullWidth: {
        width: '100vw',
        marginLeft: `calc((min(${lg}px, 100vw) - 100vw) / 2 - ${s2}px)`,

        [theme.breakpoints.up('sm')]: {
          marginLeft: `calc((min(${lg}px, 100vw) - 100vw) / 2 - ${s3}px)`,
        },
      },
    });
  },
  { name: 'NoGutters' },
);

export function NoGutters({
  fullWidth = false,
  children,
}: PropsWithChildren<Props>) {
  const classes = useStyles();

  return (
    <div
      className={clsx(classes.container, {
        [classes.fullWidth]: fullWidth,
      })}
    >
      {children}
    </div>
  );
}
