import React, { PropsWithChildren } from 'react';
import clsx from 'clsx';
import { createStyles, makeStyles } from '@material-ui/core';
import { Text } from '../Text';

type Props = {
  title: string;
  titleCentered?: boolean;
  className?: string;
};

const useStyles = makeStyles(
  () =>
    createStyles({
      titleCentered: {
        textAlign: 'center',
      },

      content: {
        marginTop: 30,
        lineHeight: 1.33,
      },
    }),
  { name: 'Paragraph' },
);

export function Paragraph({
  title,
  titleCentered = false,
  className,
  children,
}: PropsWithChildren<Props>) {
  const classes = useStyles();

  return (
    <div className={className}>
      <Text
        variant="title-bold"
        className={clsx({
          [classes.titleCentered]: titleCentered,
        })}
      >
        {title}
      </Text>
      <Text variant="text" className={classes.content}>
        {children}
      </Text>
    </div>
  );
}
