/* eslint-disable jsx-a11y/heading-has-content */
import React, { PropsWithChildren } from 'react';
import { createStyles, makeStyles } from '@material-ui/core';
import clsx from 'clsx';

type Variant = 'text' | 'title-bold' | 'title-middle' | 'badge' | 'badge-small';

export type TextProps = {
  variant?: Variant;
  className?: string;
  asHeading?: boolean;
};

const textFont = '"Brygada 1918"';
const badgeFont = 'Afacad';

const useStyles = makeStyles(
  () =>
    createStyles({
      text: {
        fontFamily: textFont,
        fontWeight: 400,
        fontSize: 19,
        lineHeight: '100%',
      },

      'title-bold': {
        fontFamily: textFont,
        fontWeight: 700,
        fontSize: 58,
        lineHeight: '100%',
      },

      'title-middle': {
        fontFamily: textFont,
        fontWeight: 700,
        fontSize: 24,
        lineHeight: '161%',
        letterSpacing: '1%',
        textDecoration: 'underline',
      },

      badge: {
        fontFamily: badgeFont,
        fontWeight: 400,
        fontSize: 18,
        lineHeight: '100%',
        letterSpacing: '30%',
      },

      get 'badge-small'() {
        return {
          ...this.badge,
          fontSize: 13,
        };
      },
    }),
  { name: 'Text' },
);

export function Text({
  children,
  className,
  asHeading = false,
  variant = 'text',
}: PropsWithChildren<TextProps>) {
  const classes = useStyles();

  const props = {
    className: clsx(classes[variant], className),
    children,
  };

  switch (variant) {
    case 'title-bold':
      return asHeading ? <h1 {...props} /> : <p {...props} />;

    case 'title-middle':
    case 'text':
      return <p {...props} />;

    case 'badge':
    case 'badge-small':
      return <span {...props} />;
  }
}
