import React from 'react';
import { createStyles, Grid, makeStyles } from '@material-ui/core';
import { NotFound } from 'src/pages';
import { CountInfo, FooterAction, NoGutters, Text } from 'src/components';
import { projectOrder, ProjectSlug, projectsMap } from 'src/projects';
import {
  BracesDiary,
  BracesDiaryOnboardingV1,
  Cinderella,
  DeliveryApp,
  IndexStandard,
  NetWorthGains,
  ParkingMeter,
  PersonalBrandingStatement,
  TestimonialBuzz,
  TribeSocia,
  Whirlpool,
  WhirlpoolInsidePass,
} from 'src/projects/project-pages';
import routes from 'src/routes';
import { BracesDiaryOnboardingV2 } from 'src/projects/project-pages/BracesDiaryOnboardingV2';

type Props = {
  projectName: string;
};

const useStyles = makeStyles(
  () =>
    createStyles({
      container: {
        marginTop: 60,
      },

      title: {
        opacity: 0,
        animation: 'fadeIn .75s ease-out .15s forwards',
        textTransform: 'uppercase',
      },

      countInfo: {
        opacity: 0,
        animation: 'fadeIn .75s ease-out .35s forwards',
        marginTop: 50,
      },

      image: {
        width: '100%',
        marginTop: 50,
        marginBottom: 50,

        opacity: 0,
        animation: 'fadeIn .75s ease-out .55s forwards',
      },

      description: {
        opacity: 0,
        animation: 'fadeIn .75s ease-out .75s forwards',
      },
    }),
  { name: 'Project' },
);

const isProjectSlug = (projectName: string): projectName is ProjectSlug =>
  projectOrder.indexOf(projectName as any) !== -1;

const getProjectPageComponent = (slug: ProjectSlug): React.ComponentType => {
  switch (slug) {
    case 'parking-meter':
      return ParkingMeter;
    case 'tribe-socia':
      return TribeSocia;
    case 'delivery-app':
      return DeliveryApp;
    case 'index-standard':
      return IndexStandard;
    case 'net-worth-gains':
      return NetWorthGains;
    case 'cinderella':
      return Cinderella;
    case 'personal-branding-statement':
      return PersonalBrandingStatement;
    case 'braces-diary':
      return BracesDiary;
    case 'testimonial-buzz':
      return TestimonialBuzz;
    case 'whirlpool':
      return Whirlpool;
    case 'whirlpool-insidepass':
      return WhirlpoolInsidePass;
    case 'braces-diary-onboarding-v1':
      return BracesDiaryOnboardingV1;
    case 'braces-diary-onboarding-v2':
      return BracesDiaryOnboardingV2;
  }
};

export function Project({ projectName }: Props) {
  const classes = useStyles();

  if (!isProjectSlug(projectName)) {
    return <NotFound />;
  }

  const project = projectsMap[projectName];

  const ProjectPage = getProjectPageComponent(projectName);

  const nextProjectIndex = () => {
    const projectIndex = projectOrder.indexOf(projectName);
    const nextIndex = projectIndex + 1;

    return nextIndex > projectOrder.length - 1 ? 0 : nextIndex;
  };

  return (
    <div key={projectName} className={classes.container}>
      <Grid
        container
        alignItems="center"
        justifyContent="center"
        direction="column"
      >
        <Grid
          item
          component={Text}
          variant="title-bold"
          className={classes.title}
        >
          {project.title}
        </Grid>

        <Grid item className={classes.countInfo}>
          <CountInfo
            number={projectOrder.indexOf(projectName) + 1}
            projectCount={projectOrder.length}
          />
        </Grid>
      </Grid>

      <NoGutters fullWidth>
        <img src={project.imageSrc} alt="" className={classes.image} />
      </NoGutters>

      <div className={classes.description}>
        <ProjectPage />
      </div>

      <FooterAction
        action={{
          label: 'NEXT PROJECT',
          href: routes.Project.build({
            name: projectOrder[nextProjectIndex()],
          }),
        }}
      />
    </div>
  );
}
