import React, { useEffect, useState } from 'react';

export default function BracesDiaryOnboardingV2Presentation() {
  const [image, setImage] = useState<string>();

  useEffect(() => {
    import('./braces-diary-onboarding-v2-presentation.svg').then((imagePath) =>
      setImage(imagePath.default),
    );
  }, []);

  return <img src={image} alt="Braces Diary Onboarding V2 Presentation" />;
}
